import"./modulepreload-polyfill-B5Qt9EMX.js";const s=document.getElementById("btn"),a=document.getElementById("input"),r=document.getElementById("result");s.addEventListener("click",async()=>{try{const t=a.value.trim();if(!t)throw new Error("Please enter the URL");if(!t.includes("github.com/"))throw new Error("Please enter a valid GitHub URL");const o=t.split("github.com/")[1].replace("/",""),e=await fetch(`http://api.github.com/users/${o}`);if(!e.ok)throw new Error("User not found");const n=await e.json();r.innerHTML=`<img src="${n.avatar_url}">
                     <h2>${n.name}</h2>`}catch(t){r.innerHTML=`<p>${t.message}</p>`}});
